helper["pro"]["createAssembly"]["html"] = String["raw"]`<html charset="UTF-8">

<head><meta name="viewport" content="width=device-width, initial-scale=1" />

<style>

    html{overflow:hidden;}

    body{line-height:30px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} span.caption{width:60px;} i{margin-left:6px;}

    input[type=checkbox]{margin-left:2px; margin-right:1px; margin-top:8px; vertical-align:top; width:13px; height:13px; accent-color:gray;}

    input{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; padding:1px 2px; width:130px; height:16.667px;} input::placeholder{color: #aaa;}

    select{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; margin-left:0px; padding-top:0px; width:55px; height:20px; font-size:13px;}

    #type-44 select{width:55px;}    #type-9100 select{width:55px;} #type-6 select{width:55px;}

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);}    

    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;}

    .combo-box{display:inline-block; position:relative;width:55px; height:20px;} .combo-list{width:100%;}

    .combo-edit{position:absolute; height:13px; width:30px; left:2px; top:7px; outline-style:none; border:0px; padding-left:2px; background-color:transparent; font-size:13px;}

    .mtips{color:#777;font-size:11px;}     

    span[name="rule"]{cursor:pointer;}

    #counter{color:green; margin-left:6px;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

</style>

<script>

    function $(a) {

        return a && '#'==a[0] && document.getElementById(a.substring(1));

    }

    function editchange(edit) {

        edit.setAttribute("value", Number(edit.value.replace('次','').replace('秒',''))); 

        apply();   

    }

    function listchange(list) {

        var edit = list.parentNode.children["edit"];

        var i = list.selectedIndex;

        edit.value = list.options[i].innerText;

        edit.setAttribute("value", list.options[i].value);

        list.selectedIndex = 0;

        apply();

    }

    function toggle_rule(e) {

        e.innerText = "黑名单:" == e.innerText ? "白名单:" : "黑名单:";

        e.value = 1 - e.value;

        apply();

    }

    function apply() {

        var e = {group:[]};

        //e.preset = Number($("#preset").value);

        e.time = Number($("#time").value);

        e.count = Number($("#count").children["edit"].getAttribute("value"));

        e.interval = Number($("#interval").children["edit"].getAttribute("value"));

        e.strict = $("#strict").checked; 

        e.energy = $("#energy").checked; 

        e.reset = $("#reset").checked;        

        for(var div of $("#group").children) {

            var g = {};

            g.id = Number(div.id.substring(5)),

            g.selected = div.children["selected"].checked,

            g.preset = Number(div.children["preset"].value);

            g.min = Number(div.children["min"].value),

            g.max = Number(div.children["max"].value),

            g.rule = div.children["rule"].value,         

            g.filter = div.children["filter"].value;

            e.group.push(g);

        }

        parent.helper.pro.createAssembly.apply(e);

    }

    function _html(g) {

        for (var options = "", i=g.cmin; i<=g.cmax; i=i+g.step){ options += '<option value=' + i + '>' + i + '级</option>';}

       for (var lists = "", i=-1; i<=9; i++){ lists += '<option value=' + i + '>' + (i==-1 ? '单兵' : (i==0 ? '自动' : '编队'+ i)) + '</option>';}

        return '<div id=type-' + g.id + '>' +

               '    <input type="checkbox" name="selected" onclick="apply()"><span class="caption">' + g.text + '</span>' +

               '    <i></i><span>编队:</span>' + 

               '    <select name="preset" onchange="apply()">' + lists + '</select>' + 

               '    <i></i><span>最低:</span>' + 

               '    <select name="min" onchange="apply()">' + options + '</select>' + 

               '    <i></i><span>最高:</span>' + 

               '    <select name="max" onchange="apply()">' + options + '</select>' +

               '    <i></i><span name="rule" onclick="toggle_rule(this)">黑名单:</span>' + 

               '    <input name="filter" placeholder="空格分隔玩家" onchange="apply()">' +

               '</div>';

    }

    function render(e) {

        for (var html="", i=0; i<e.group.length; ++i){ html = html.concat(_html(e.group[i]));}

        $("#group").innerHTML = html;        

        //$("#preset").value = e.param.preset;

        $("#time").value = e.param.time;

        $("#interval").children["edit"].value = e.param.interval + '秒';

        $("#interval").children["edit"].setAttribute("value", e.param.interval);

        $("#interval").children["list"].value = '';        

        $("#count").children["edit"].value = (99999 == e.param.count) ? '无限次' : e.param.count + '次';

        $("#count").children["edit"].setAttribute("value",e.param.count);

        $("#count").children["list"].value = '';

        $("#strict").checked = e.param.strict;

        $("#energy").checked = e.param.energy;

        $("#reset").checked = e.param.reset;

        $("#counter").innerText = e.state.counter ? '已打' + e.state.counter +'次' : '';

        $("#counter").style.color = e.state.counter >= e.param.count ? "green" : e.state.running ? "purple" : "black";

        $("#state").innerText = e.state.running ? "运行中" : "未运行";

        $("#state").style.backgroundColor = e.state.running ? "greenyellow" : "#aaa";

        $("#state").style.borderRadius = "2px";

        $("#action").innerText = e.state.running ? "停止" : "启动";

        for(var g of e.group) {

            var children = $("#type-"+g.id).children;

            children["selected"].checked= g.selected;

            children["preset"].value = g.preset;

            children["min"].value = g.min;

            children["max"].value = g.max;

            children["rule"].innerText = g.rule ? "白名单:" : "黑名单:";

            children["rule"].value = g.rule;

            children["filter"].value = g.filter;

        }

    }

    function action() {

        var o = parent.helper.pro.createAssembly;

        o.state.running ? o.suspend() : o.startup();

    }

</script>

</head>

<body>

    <h3>自动发起集结</h3>

    <div class="panel">

       <span>时间:</span>

        <select id="time" onchange="apply()">

            <option value="60">1分</option>

            <option value="180">3分</option>

            <option value="300">5分</option>

            <option value="600">10分</option>

            <option value="1800">30分</option>

        </select>

        <i></i><span>间隔:</span>

        <div id="interval" class="combo-box">

            <select name="list" class="combo-list" onchange="listchange(this)">

                <option value="5">5秒</option>

                <option value="10">10秒</option>

                <option value="30">30秒</option>

                <option value="60">60秒</option>

                <option value="300">300秒</option>

                <option value="600">600秒</option>

            </select>

            <input name="edit" class="combo-edit" onchange="editchange(this)">

        </div>

        <i></i><span>次数:</span>

        <div id="count" class="combo-box">

            <select name="list" class="combo-list" onchange="listchange(this)">

                <option value="1">1次</option>

                <option value="5">5次</option>

                <option value="10">10次</option>

                <option value="50">50次</option>

                <option value="99999">无限次</option>

            </select>

            <input name="edit" class="combo-edit" onchange="editchange(this)">

        </div>

        <input type="checkbox" id="reset" onclick="apply()"><span>次日归零</span>

        <input type="checkbox" id="strict" onclick="apply()"><span>检查出征</span>

        <input type="checkbox" id="energy" onclick="apply()"><span>补充体力</span>

        <span id="counter">999次</span>

   <br><span class="mtips">* 同时勾选惧星的话优先打惧星10次后才打其它,间隔时间和次数也可以手动输入数字</span>

    </div>

    <div id="group" class="panel">

        <div>

            <input type="checkbox" name="selected" onclick="apply()"><span class="caption">战锤-4000</span>

            <span>编队:</span><select name="preset" onchange="apply()"><option value=1>编队1</option></select>

            <span>最低:</span>

            <select name="min" onchange="apply()">

                <option value="67">67级</option>

            </select>

            <span>最高:</span>

            <select name="max" onchange="apply()">

                <option value="67">67级</option>

            </select>

            <span name="rule" onclick="toggle_rule(this)">黑名单:</span>

            <input name="filter" placeholder="空格分隔玩家" onchange="apply()">

        </div>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
