helper["pro"]['helpRefugee']['html'] = String["raw"]`<html charset="UTF-8">

<head><style>

    html{overflow:hidden;}

    body{line-height:30px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} span.caption{width:82px;}

    input[type=checkbox]{margin-left:2px; margin-right:1px; margin-top:8px; vertical-align:top; width:13px; height:13px; accent-color:gray;}

    select{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; margin-left:0px; padding-top:0px; width:65px; height:20px; font-size:13px;}

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);}



    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;}

    .combo-box{display:inline-block; position:relative;width:65px; height:20px;} .combo-list{width:100%;}

    .combo-edit{position:absolute; height:13px; width:45px; left:2px; top:7px; outline-style:none; border:0px; padding-left:2px; background-color:transparent; font-size:13px;}

    .mtips{color:#777;font-size:11px;}

    #counter{color:green; margin-left:120px; width:120px;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px} 

</style>     

<script>

    function $(a) {

        return a && '#'==a[0] && document.getElementById(a.substring(1));

    }

    function editchange(edit) {

        edit.setAttribute("value", Number(edit.value.replace('次','').replace('秒',''))); 

        apply();   

    }

    function listchange(list) {

        var edit = list.parentNode.children["edit"];

        var i = list.selectedIndex;

        edit.value = list.options[i].innerText;

        edit.setAttribute("value", list.options[i].value);

        list.selectedIndex = 0;

        apply();

    }

    function apply() {

        var e = {group:[]};

        e.preset = Number($("#preset").value);

        e.time = Number($("#time").value);

        e.count = Number($("#count").children["edit"].getAttribute("value"));

        e.interval = Number($("#interval").children["edit"].getAttribute("value"));

        e.strict = $("#strict").checked; 

        e.energy = $("#energy").checked;

        e.reset = $("#reset").checked;

        parent.helper.pro.helpRefugee.apply(e);

    }

    function render(e) {

        $("#preset").value = e.param.preset;

        $("#time").value = e.param.time;

        $("#count").children["edit"].value = (99999 == e.param.count) ? '无限次' : e.param.count + '次';

        $("#count").children["edit"].setAttribute("value",e.param.count);

        $("#count").children["list"].value = '';

        $("#interval").children["edit"].value = e.param.interval + '秒';

        $("#interval").children["edit"].setAttribute("value", e.param.interval);

        $("#interval").children["list"].value = '';

        $("#strict").checked = e.param.strict;

        $("#energy").checked = e.param.energy;

        $("#reset").checked = e.param.reset;

        $("#counter").innerText = e.state.counter ? '已拯救' + e.state.counter +'次' : '';

        $("#counter").style.color = e.state.counter >= e.param.count ? "green" : e.state.running ? "purple" : "black";

        $("#state").innerText = e.state.running ? "运行中" : "未运行";

        $("#state").style.backgroundColor = e.state.running ? "greenyellow" : "#aaa";

        $("#state").style.borderRadius = "2px";

        $("#action").innerText = e.state.running ? "停止" : "启动";

    }

    function action() {

        var o = parent.helper.pro.helpRefugee;

        o.state.running ? o.suspend() : o.startup();

    }

</script>

</head>

<body>

    <h3>自动拯救难民</h3>

    <div class="panel">

        <span>编队:</span>

        <select id="preset" onchange="apply()">

            <option value=-1>单兵</option>

            <option value=1>编队1</option>

            <option value=2>编队2</option>

            <option value=3>编队3</option>

            <option value=4>编队4</option>

            <option value=5>编队5</option>

            <option value=6>编队6</option>

            <option value=7>编队7</option>

            <option value=8>编队8</option>

            <option value=9>编队9</option>

            <option value=0>自动</option>

        </select>

        <span style="margin-left:10px">时间:</span>

        <select id="time" onchange="apply()">

            <option value="60">1分</option>

            <option value="180">3分</option>

            <option value="300">5分</option>

            <option value="600">10分</option>

            <option value="1800">30分</option>

        </select>

        <span style="margin-left:10px">间隔:</span>

        <div id="interval" class="combo-box">

            <select name="list" class="combo-list" onchange="listchange(this)">

                <option value="5">5秒</option>

                <option value="10">10秒</option>

                <option value="15">15秒</option>

                <option value="30">30秒</option>

                <option value="60">60秒</option>

                <option value="300">300秒</option>

                <option value="600">600秒</option>

            </select>

            <input name="edit" class="combo-edit" onchange="editchange(this)">

        </div>

        <span style="margin-left:10px">次数:</span>

        <div id="count" class="combo-box">

            <select name="list" class="combo-list" onchange="listchange(this)">

                <option value="1">1次</option>

                <option value="5">5次</option>

                <option value="8">8次</option>

                <option value="10">10次</option>

                <option value="15">15次</option>

                <option value="50">50次</option>

                <option value="99999">无限次</option>

            </select>

            <input name="edit" class="combo-edit" onchange="editchange(this)">

        </div>

        <br>

        <input type="checkbox" id="strict" onclick="apply()"><span>检查出征</span>

        <input type="checkbox" id="energy" onclick="apply()"><span>补充体力</span>

        <input type="checkbox" id="reset" onclick="apply()"><span>每日清零</span>

        <i id="counter">已拯救难民99999次</i>

   <br><span class="mtips">* 提示：间隔时间和次数也可以手动输入数字</span>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
