helper["pro"]["relicItem"]["html"] = String["raw"]`<html  charset="UTF-8">

<head>

<style>

    html{overflow:hidden;}

    body{line-height:24px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} i{margin-left:8px;}

    select{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; height:20px; font-size:13px;} 

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);}

    ul{display:flex; margin:4px; list-style-type:none; flex-flow:wrap; padding-inline-start:0px;}

    li{margin:4px; margin-left:8px; padding-left:4px; text-align:left; width:150px; height:24px; background:#ddd; border-radius:2px;}



    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-top:6px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;}

    .scrollview{overflow-x:auto; overflow-y:auto;}

    .scrollview::-webkit-scrollbar{width:8px; height:8px;} 

    .scrollview::-webkit-scrollbar-track {background:rgb(240, 240, 240); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb {background:rgb(208, 208, 208); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:hover{background:rgb(176, 176, 176); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:active {background:rgb(144, 144, 144); border-radius:8px;}

    .mtips{color:#777;font-size:11px;margin-left:12px;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

    #army{width:60px;} #level{width:280px;} #content{height:170px;} #history{height:70px;} 

</style>

<script src="${helper["jquery_url"]}"></script>

<script>

    function init() {

        $("#level").val(parent.helper.pro.relicItem.fortressLevel);

        $("#items").sortable({update:apply});

    }



    function apply() {

        var i = $("#level").val(), items = [];

        for(var li of $("#items").children()){ items.push(li.value);}

        parent.helper.pro.relicItem.apply(Number(i), items);

    }



    function select() {

        var army = $("#army").val();

        var level = $("#level").val();

        parent.helper.pro.relicItem.select(Number(army), Number(level));

    }



    function render(setting, history, state) {

        $("#army").val(setting.army);



        $("#items").html("");

        var i = $("#level").val();

        var a = setting.item[i] ?? [];

        for(var e of a) {

            var li = document.createElement('li');

            li.value = e.id;

            li.innerText = e.name;

            $("#items").append(li);

        }



        var html = "";

        history.forEach(e=>html += "" == html ? e : "<br>"+e);

        $("#history").html(html);



        $("#state").text(state.running ? "运行中" : "未运行");

        $("#state").css("backgroundColor", state.running ? "greenyellow" : "#aaa");

        $("#state").css("borderRadius", "2px");



        $("#action").text(state.running ? "停止" : "启动");

    }



    function action() {

        var o = parent.helper.pro.relicItem;

        o.state.running ? o.suspend() : o.startup();

    }



</script>

</head>

<body onload="init()">

    <h3>领取遗迹道具</h3>

    <div class="panel">

        <span style="margin-left:12px"></span>

        <span>士兵类别:</span>

        <select id="army" onchange="select()">

            <option value=1>陆军</option>

            <option value=2>海军</option>

            <option value=3>空军</option>

        </select>

        <i></i><i></i><i></i>

        <span>道具排序:</span>

        <select id="level" onchange="select()">

            <option value=1>遗迹等级1</option>

            <option value=2>遗迹等级2</option>

            <option value=3>遗迹等级3</option>

            <option value=4>遗迹等级4</option>

            <option value=5>遗迹等级5</option>

            <option value=6>遗迹等级6</option>

        </select>

        <div class="scrollview" id="content">

        <span class="mtips">* 提示：拖动可以排列道具领取顺序</span>

            <ul class="list" id="items" onsortupdate="apply()">

                <li>1</li>

                <li>2</li>

                <li>3</li>

                <li>4</li>

                <li>5</li>

            </ul>

        </div> 

    </div>

    <div class="panel">

        <div class="scrollview" id="history">

        </div>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
