helper["pro"]["c8worldBoss"]["html"] = String["raw"]`<html charset="UTF-8">

<head>

<style>

    html{overflow:hidden;}

    body{line-height:30px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:text;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} span.caption{width:80px;} i{margin-left:8px;}

    input[type=checkbox]{margin-left:2px; margin-right:1px; margin-top:8px; vertical-align:top; width:13px; height:13px; accent-color:gray;}

    select{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; margin-left:0px; padding-top:0px; width:65px; height:20px; font-size:13px;} 

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);} 



    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;}

    .combo-box{display:inline-block; position:relative; width:60px; height:20px;} .combo-list{width:100%;}

    .combo-edit{position:absolute; height:13px; width:40px; left:2px; top:7px; outline-style:none; border:0px; padding-left:2px; background-color:transparent; font-size:13px;}

    .tips{color:purple;font-size:12px;}

    #skinid{width:100px;} 

    #counter{display:inline-block; margin-left:8px; color:green; width:70px;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

</style>

<script>

    function $(a) {

        return a && '#'==a[0] && document.getElementById(a.substring(1));

    }



    function editchange(edit) {

        edit.setAttribute("value", Number(edit.value.replace('次',''))); 

        apply();   

    }



    function listchange(list) {

        var edit = list.parentNode.children["edit"];

        var i = list.selectedIndex;

        edit.value = list.options[i].innerText;

        edit.setAttribute("value", list.options[i].value);

        list.selectedIndex = 0;

        apply();

    }



    function apply() {

        var setting = {presets:[]};

        setting.presets[0] = Number($('#preset-1').value);

        setting.presets[1] = Number($('#preset-2').value);

        setting.presets[2] = Number($('#preset-3').value);

        setting.eindex = Number($('#eindex').value);

        setting.skinid = Number($('#skinid').value);

        setting.count = Number($('#count').children['edit'].getAttribute('value'));

        setting.strict = $('#strict').checked;

        setting.energy = $('#energy').checked;

        parent.helper.pro.c8worldBoss.apply(setting);

    }



    function render(setting, state, skinList) {

        var html = "<option value=-1>不切换</option>";

        for(var e of skinList){ html += '<option value=' + e.id + '>' + e.name + '</option>';}

        $('#skinid').innerHTML = html;



        $('#preset-1').value = setting.presets[0];

        $('#preset-2').value = setting.presets[1];

        $('#preset-3').value = setting.presets[2];

        $('#eindex').value = setting.eindex;

        $('#skinid').value = setting.skinid;       

        $('#count').children["edit"].value = (99999 == setting.count) ? '无限次' : setting.count + '次';

        $('#count').children["edit"].setAttribute('value', setting.count);

        $('#count').children["list"].value = '';

        $('#strict').checked = setting.strict;

        $('#energy').checked = setting.energy;

        $('#counter').innerText = state.counter ? '已攻击' + state.counter +'次' : '';

        $('#counter').style.color = state.counter >= setting.count ? 'green' : state.running ? 'purple' : 'black';



        $('#state').innerText = state.running ? '运行中' : '未运行';

        $('#state').style.backgroundColor = state.running ? 'greenyellow' : '#aaa';

        $('#state').style.borderRadius = '2px';



        $('#action').innerText = state.running ? '停止' : '启动';

    }



    function action() {

        var o = parent.helper.pro.c8worldBoss;

        o.state.running ? o.suspend() : o.startup();

    }

</script>

</head>

<body>

    <h3>击败混乱之源</h3>

    <div class="panel">

        <span>陆军元帅:</span>

        <select id="preset-1" onchange="apply()">

            <option value=-1>单兵</option>

            <option value=1>编队1</option>

            <option value=2>编队2</option>

            <option value=3>编队3</option>

            <option value=4>编队4</option>

            <option value=5>编队5</option>

            <option value=6>编队6</option>

            <option value=7>编队7</option>

            <option value=8>编队8</option>

            <option value=9>编队9</option>

            <option value=0>自动</option>

        </select>

        <i></i>

        <span>海军元帅:</span>

        <select id="preset-2" onchange="apply()">

            <option value=-1>单兵</option>

            <option value=1>编队1</option>

            <option value=2>编队2</option>

            <option value=3>编队3</option>

            <option value=4>编队4</option>

            <option value=5>编队5</option>

            <option value=6>编队6</option>

            <option value=7>编队7</option>

            <option value=8>编队8</option>

            <option value=9>编队9</option>

            <option value=0>自动</option>

        </select>

        <i></i>

        <span>空军元帅:</span>

        <select id="preset-3" onchange="apply()">

            <option value=-1>单兵</option>

            <option value=1>编队1</option>

            <option value=2>编队2</option>

            <option value=3>编队3</option>

            <option value=4>编队4</option>

            <option value=5>编队5</option>

            <option value=6>编队6</option>

            <option value=7>编队7</option>

            <option value=8>编队8</option>

            <option value=9>编队9</option>

            <option value=0>自动</option>

        </select>

        <i></i>

        <span>攻击次数:</span>

        <div id="count" class="combo-box">

            <select name="list" class="combo-list" onchange="listchange(this)">

                <option value=0>0次</option>

                <option value=5>5次</option>

            </select>

            <input name="edit" class="combo-edit" onchange="editchange(this)">

        </div>

        <br>

        <span>切换强化:</span>

        <select id="eindex" onchange="apply()">

            <option value="0">方案1</option>

            <option value="1">方案2</option>

            <option value="2">方案3</option>

            <option value="3">方案4</option>

        </select>

        <i></i>

        <span>切换皮肤:</span>

        <select id="skinid" onchange="apply()">

        </select>

        <i></i>

        <input type="checkbox" id="strict" onclick="apply()"><span>检查出征</span>

        <input type="checkbox" id="energy" onclick="apply()"><span>补充体力</span>

        <i></i>

        <span id="counter"></span>

        <div class="tips">1.请先收藏好要切换的皮肤 2.在英雄技能栏2组安装打BOSS技能,攻击时会切换成技能栏2</div>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
