helper["pro"]['avoidAttacked']["html"] = String['raw']`<html charset="UTF-8">

<head>

<style>

    html{overflow:hidden;}

    body{line-height:30px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:text;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} span.caption{width:80px;} i{margin-left:8px;}

    input[type=checkbox]{margin-left:2px; margin-right:1px; margin-top:8px; vertical-align:top; width:13px; height:13px; accent-color:gray;}

    input{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; padding:1px 2px; width:120px; height:16.667px;}

    select{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; margin-left:0px; padding-top:0px; width:65px; height:20px; font-size:13px;} 

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);} 

    .mtips{color:#FF9900;font-size:12px;}  

    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;} 

    .combo-box{display:inline-block; position:relative; width:65px; height:20px;} .combo-list{width:100%;}

    .combo-edit{position:absolute; height:13px; width:45px; left:2px; top:7px; outline-style:none; border:0px; padding-left:2px; background-color:transparent; font-size:13px;}

    .scrollview{overflow-x:auto; overflow-y:auto;}

    .scrollview::-webkit-scrollbar{width:8px; height:8px;} 

    .scrollview::-webkit-scrollbar-track {background:rgb(240, 240, 240); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb {background:rgb(208, 208, 208); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:hover{background:rgb(176, 176, 176); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:active {background:rgb(144, 144, 144); border-radius:8px;} 



    #setting{padding-top:6px; padding-bottom:6px;} 

    #history{line-height:24px; height:200px;} #teams{width:64px;} #skinid{width:90px;} 

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

    .new-option {margin-top: 6px; display: block;}

</style>

<script>

    function $(a) {

        return a && '#'==a[0] && document.getElementById(a.substring(1));

    }



    function apply(e) {

        var setting = {option:{}};

        setting.option.shield = $("#shield").checked;

        setting.option.movecity = $("#movecity").checked;

        setting.option.march = $("#march").checked;

        setting.option.skipCompare = $("#skipCompare").checked;

        setting.option.defense = $("#defense").checked;

        setting.itemid = Number($("#itemid").value);

        setting.block = Number($("#block").value);

        setting.teams = Number($("#teams").value);

        setting.skinid = Number($("#skinid").value);

        parent.helper.pro.avoidAttacked.apply(setting);

    }



    function render(setting, history, state, skinList) {

        var html = '<option value="-1">不切换</option>';

        for(var e of skinList) html += "<option value='" + e.id + "'>" + e.name + "</option>";

        $("#skinid").innerHTML = html;



        $("#shield").checked = setting.option.shield;

        $("#movecity").checked = setting.option.movecity;

        $("#march").checked = setting.option.march;

        $("#defense").checked = setting.option.defense;

        $("#skipCompare").checked = setting.option.skipCompare && !setting.option.defense;



        $("#itemid").value = setting.itemid;

        $("#block").value = setting.block;

        $("#teams").value = setting.teams;

        $("#skinid").value = setting.skinid;



        $("#itemid").disabled = !setting.option.shield;

        $("#itemid-label").style.color = !setting.option.shield ? "#aaa" : "black";



        $("#block").disabled = !setting.option.movecity;

        $("#block-label").style.color = !setting.option.movecity ? "#aaa" : "black";



        $("#teams").disabled = !setting.option.march;

        $("#teams").style.color = !setting.option.march ? "#aaa" : "black";

        $("#teams-label").style.color = !setting.option.march ? "#aaa" : "black";



        $("#skipCompare").disabled = setting.option.defense;

        $("#skipCompare").style.color = setting.option.defense ? "#aaa" : "black";

        $("#skipCompare-label").style.color = setting.option.defense ? "#aaa" : "black";



        var html = "";

        history.forEach(e=>html += "" == html ? e : "<br>"+e);

        $("#history").innerHTML = html;



        $("#state").innerText = state.running ? "运行中" : "未运行";

        $("#state").style.backgroundColor = state.running ? "greenyellow" : "#aaa";

        $("#state").style.borderRadius = "2px";



        $("#action").innerText = state.running ? "停止" : "启动";

    }



    function goto(e) {

        var a = e.innerText.split(',');

        parent.helper.tools.gotoWorldAndClick({x:a[0], y:a[1]});

        parent.helper.dialog.close();

    }



    function action() {

        var o = parent.helper.pro.avoidAttacked;

        o.state.running ? o.suspend() : o.startup();

    }

</script>

</head>

<body>

    <h3>免受攻击保护</h3>

    <div class="panel" id="setting">

        <input type="checkbox" id="shield" onclick="apply()"><span>护盾</span>

        <span id="itemid-label">道具:</span>

        <select id="itemid" name="itemid" onchange="apply()">

        <option value=0>自动</option>

            <option value=200004>4小时</option>

            <option value=200005>8小时</option>

            <option value=200006>24小时</option>

        </select>

        <i></i>

        <input type="checkbox" id="movecity" onclick="apply()"><span>迁城</span>

        <span id="block-label">区域:</span>

        <select id="block" name="block" onchange="apply()">

            <option value=0>自动</option>

            <option value=1>区域1</option>

            <option value=2>区域2</option>

            <option value=3>区域3</option>

            <option value=4>区域4</option>

            <option value=5>区域5</option>

            <option value=6>区域6</option>

            <option value=7>区域7</option>

            <option value=8>区域8</option>

            <option value=9>区域9</option>

        </select>

        <i></i>

        <input type="checkbox" id="march" onclick="apply()"><span>出征</span>

        <span id="teams-label">队列:</span>

        <input id="teams" placeholder="如123456" onchange="apply()">

        <div class="new-option">

        <input type="checkbox" id="defense" onclick="apply()"><span>切换城防</span>

        <span id="skinid-label">皮肤:</span>

        <select id="skinid" name="skinid" onchange="apply()">

        </select><i></i>

            <input type="checkbox" id="skipCompare" onclick="apply()">

            <span id="skipCompare-label">跳过双方战力判断</span>

        </div>

        <div class="mtips">

            * 启用"跳过双方战力判断"后，被攻击时将直接执行保护措施，不进行预判胜率后才决定是否保护<br>

        </div>

    </div>



    <div class="panel">

        <div class="scrollview" id="history">

        </div>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
