helper["pro"]['sustainAttack']["html"] = String["raw"]`<html charset="UTF-8">

<head>

<style>

    html{overflow:hidden;}

    body{line-height:30px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} i{margin-left:8px;}

    input[type=checkbox]{margin-left:2px; margin-right:1px; margin-top:9px; vertical-align:top; width:13px; height:13px; accent-color:gray;}

    select{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; margin-left:0px; padding-top:0px; width:65px; height:20px; font-size:13px;}

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);}

    .mtips{color:#777;font-size:12px;} 

    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;}

    .combo-box{display:inline-block; position:relative;width:65px; height:20px;} .combo-list{width:100%;}

    .combo-edit{position:absolute; height:13px; width:45px; left:2px; top:7px; outline-style:none; border:0px; padding-left:2px; background-color:transparent; font-size:13px;}



    #counter{color:green; margin-left:185px; width:120px;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

</style>

<script>

    function $(a) {

        return a && '#'==a[0] && document.getElementById(a.substring(1));

    }



    function editchange(edit) {

        edit.setAttribute("value", Number(edit.value.replace('次','').replace('级',''))); 

        apply();   

    }



    function listchange(list) {

        var edit = list.parentNode.children["edit"];

        var i = list.selectedIndex;

        edit.value = list.options[i].innerText;

        edit.setAttribute("value", list.options[i].value);

        list.selectedIndex = 0;

        apply();

    }



    function apply() {

        var setting = {};

        setting.lujun = $("#lujun").checked;

        setting.haijun = $("#haijun").checked;

        setting.kongjun = $("#kongjun").checked;

        setting.max = Number($("#max").children["edit"].getAttribute("value"));

        setting.min = Number($("#min").children["edit"].getAttribute("value"));

        setting.fortress = $("#fortress").checked;

        setting.ptower = $("#ptower").checked;

        setting.btower = $("#btower").checked;

        setting.preset = Number($("#preset").value);

        setting.count = Number($("#count").children["edit"].getAttribute("value"));



        parent.helper.pro.sustainAttack.apply(setting);

    }



    function render(setting, state) {

        $("#lujun").checked = setting.lujun;

        $("#haijun").checked = setting.haijun;

        $("#kongjun").checked = setting.kongjun;

        $("#max").children["edit"].value = setting.max + '级';

        $("#max").children["edit"].setAttribute("value", setting.max);

        $("#max").children["list"].value = '';

        $("#min").children["edit"].value = setting.min + '级';

        $("#min").children["edit"].setAttribute("value", setting.min);

        $("#min").children["list"].value = '';

        $("#fortress").checked = setting.fortress;

        $("#ptower").checked = setting.ptower;

        $("#btower").checked = setting.btower;

        $("#preset").value = setting.preset;

        $("#count").children["edit"].value = 99999 == setting.count ? '无限次' : setting.count + '次';

        $("#count").children["edit"].setAttribute("value", setting.count);

        $("#count").children["list"].value = '';

        $("#coord").innerText = setting.target ? setting.target.x+','+setting.target.y : '';



        $("#counter").innerText = state.counter ? '已攻击' + state.counter +'次' : '';

        $("#counter").style.color = state.counter >= setting.count ? "green" : state.running ? "purple" : "black";

        $("#state").innerText = state.running ? (state.paused ? "暂停" : "运行中") : "未运行";

        $("#state").style.backgroundColor = state.running ? (state.paused ? "yellow" : "greenyellow") : "#aaa";

        $("#state").style.borderRadius = "2px";

        $("#action").innerText = state.running ? "停止" : "启动";

    }



    function action() {

        var o = parent.helper.pro.sustainAttack;

        o.state.running ? o.suspend() : o.startup();

    }



    function goto(e) {

        e = e.innerText.split(',');   

        e.length == 2 && (parent.helper.pro.sustainAttack.goto({x:e[0], y:e[1]}), parent.helper.dialog.close());

    }

</script>

</head>

<body>

    <h3>连续攻击建筑</h3>

    <div class="panel">

        <div>

            <span>兵种:</span>

            <input type="checkbox" id="lujun" onclick="apply()"><label for="lujun">陆军</label>

            <input type="checkbox" id="haijun" onclick="apply()"><label for="haijun">海军</label>

            <input type="checkbox" id="kongjun" onclick="apply()"><label for="kongjun">空军</label>

            <i></i>

            <span>最高:</span>

            <div id="max" class="combo-box">

                <select name="list" class="combo-list" onchange="listchange(this)">

                    <option value="103">103级</option>

                    <option value="102">102级</option>

                    <option value="101">101级</option>

                    <option value="100">100级</option>

                    <option value="90">90级</option>

                    <option value="80">80级</option>

                    <option value="70">70级</option>

                    <option value="60">60级</option>

                    <option value="50">50级</option>

                    <option value="40">40级</option>

                    <option value="30">30级</option>

                    <option value="20">20级</option>

                    <option value="10">10级</option>

                </select>

                <input name="edit" class="combo-edit" onchange="editchange(this)">

            </div>

            <i></i>

            <span>最低:</span>

            <div id="min" class="combo-box">

                <select name="list" class="combo-list" onchange="listchange(this)">

                    <option value="100">100级</option>

                    <option value="90">90级</option>

                    <option value="80">80级</option>

                    <option value="70">70级</option>

                    <option value="60">60级</option>

                    <option value="50">50级</option>

                    <option value="40">40级</option>

                    <option value="30">30级</option>

                    <option value="20">20级</option>

                    <option value="10">10级</option>

                </select>

                <input name="edit" class="combo-edit" onchange="editchange(this)">

            </div>

        </div>

        <div>

            <span>建筑:</span>

            <input type="checkbox" id="fortress" onclick="apply()"><label for="fortress">堡垒</label>

            <input type="checkbox" id="ptower" onclick="apply()"><label for="ptower">电站</label>

            <input type="checkbox" id="btower" onclick="apply()"><label for="btower">Ｂ塔</label>

            <i></i>

            <span>编队:</span>

            <select id="preset" onchange="apply()">

                <option value=1>单兵</option>

                <option value=2>一键</option>

                <option value=3>自动</option>

                <option value=4>主力</option>

            </select>

            <i></i>

            <span>次数:</span>

            <div id="count" class="combo-box">

                <select name="list" class="combo-list" onchange="listchange(this)">

                    <option value="1">1次</option>

                    <option value="5">5次</option>

                    <option value="99999">无限次</option>

                </select>

                <input name="edit" class="combo-edit" onchange="editchange(this)">

            </div>

        </div>

        <div>

            <span>坐标:</span><a id="coord" href="javascript:void(0)" onclick="goto(this)"></a><i></i>

            <span id="counter"></span><br><span class="mtips">* 点击要攻击的建筑,在弹出的面板上点击连续攻击按钮</span>

        </div>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
