helper['pro']["treasureShop"]['html'] = String["raw"]`<html charset="UTF-8">

<head>

<style>

    html{overflow:hidden;}

    body{line-height:25px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} span.caption{width:82px;} i{margin-left:8px;}

    input{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; padding:1px 2px; width:40px; height:15px; font-size:13px; margin-left:4px;}

    input[type=checkbox]{margin-left:2px; margin-right:1px; margin-top:6px; vertical-align:top; width:13px; height:13px; accent-color:gray;}

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);}



    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;}

    .scrollview{overflow-x:auto; overflow-y:auto;}

    .scrollview::-webkit-scrollbar{width:8px; height:8px;} 

    .scrollview::-webkit-scrollbar-track {background:rgb(240, 240, 240); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb {background:rgb(208, 208, 208); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:hover{background:rgb(176, 176, 176); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:active {background:rgb(144, 144, 144); border-radius:8px;} 

    .item{display:inline-block; height:25px;}



    #items{height:180px;} #history{line-height:24px; height:100px;} #tips{ color:#FF9900;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

    span[name="name"]{width:156px} span[name="price"]{width:120px} span[name="discount"]{width:110px} span[name="count"]{color:purple;}

</style>

<script>

    function $(a) {

        return a && '#'==a[0] && document.getElementById(a.substring(1));

    }



    function apply() {

        var e = {items:[]};

        for(var div of $("#items").children) {

            e.items.push({id:Number(div.id), selected:div.children["selected"].checked});

        }

        e.interval = Number($("#interval").value)*1000;

        parent.helper.pro.treasureShop.apply(e);

    }



    function _html(item) {

        return '<div class="item" id="' + item.id + '">' +

                   '<input name="selected" type="checkbox" onclick="apply()">' +

                   '<span name="name"></span><span name="price"></span><span name="discount"></span><span name="count"></span>' +

               '</div>';

    }



    function render(items, history, state, interval) {

        for (var html="", i=0; i<items.length; ++i){ html = html.concat(_html(items[i]));}

        $("#items").innerHTML = html;



        for (var item of items) {

            var e = $('#'+item.id);

            e.children["selected"].checked = item.selected;

            e.children["name"].innerText = item.name;

            e.children["price"].innerText = '价格：' + item.price + '钻石';

            e.children["discount"].innerText = '折扣：' + item.discount + '%';

            for(var c of state.counter){ c.id==item.id && c.count>0 && (e.children["count"].innerText='已购买'+c.count+'次');}

        }



        html = "";

        history.forEach(e=>html += "" == html ? e : "<br>"+e);

        $("#history").innerHTML = html;

        $("#interval").value = interval/1000;

        $("#state").innerText = state.running ? "运行中" : "未运行";

        $("#state").style.backgroundColor = state.running ? "greenyellow" : "#aaa";

        $("#state").style.borderRadius = "2px";



        $("#action").innerText = state.running ? "停止" : "启动";

    }



    function action() {

        var o = parent.helper.pro.treasureShop;

        o.state.running ? o.suspend() : o.startup();

    }

</script>

</head>

<body>

    <h3>宝藏商店道具</h3>

    <div class="panel">

        <div class="scrollview" id="items">

            <div class="item" id="11001">

            </div>

        </div>

     <div><span>检测商店间隔时间:</span><i></i>

     <input id="interval" onchange="apply()">秒</div>

   <span id="tips">该功能会频繁与服务器交互，间隔时间太短可能有封号风险，建议不低于50秒!</span>

    </div>

    <div class="panel">

        <div class="scrollview" id="history">

        </div>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
