helper["pro"]['dwarfMiner']["html"] = String["raw"]`<html charset="UTF-8">

<head>

<style>

    html{overflow:hidden;}

    body{line-height:25px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} span.caption{width:80px;} i{margin-left:8px;}

    span[name="cname"]{width:156px;} span[name="vtime"]{width:100px;} span[name="expire"]{width:160px;}

    input[type=radio]{margin-left:2px; margin-right:1px; margin-top:6px; vertical-align:top; width:13px; height:13px; accent-color:gray;}

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);}



    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;} 

    .scrollview{overflow-x:auto; overflow-y:auto;}

    .scrollview::-webkit-scrollbar{width:8px; height:8px;} 

    .scrollview::-webkit-scrollbar-track {background:rgb(240, 240, 240); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb {background:rgb(208, 208, 208); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:hover{background:rgb(176, 176, 176); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:active {background:rgb(144, 144, 144); border-radius:8px;} 



    #chest{height:104px;} #history{line-height:24px; height:140px;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

</style>

<script>

    function $(a) {

        return a && '#'==a[0] && document.getElementById(a.substring(1));

    }



    function onTimer() {

        function format(t) {

            var h = Math.floor(t/3600);

            var m = Math.floor((t-h*3600)/60);

            var s = t-h*3600-m*60;

            return (100+h).toString().substring(1) + ':' + (100+m).toString().substring(1) + ':' + (100+s).toString().substring(1);

        }



        for (var e of $("#chest").children) {

            var o = e.children["expire"];

            o.value && o.value>parent.ServerTime && (o.innerText = format(o.value-parent.ServerTime));

            o.value && o.value<=parent.ServerTime && (o.innerText = '待领取');

        } 

    }



    function apply(e) {

        var id = e.parentNode.id;

        id && parent.helper.pro.dwarfMiner.apply(id.substring(6));

    }



    function render(setting, chest, history, state) {

        var html="";

        chest.forEach(e=>{

            html += '<div id="index_' + e.cIndex + '">';

            html += '<input type="radio" name="prior" onclick="apply(this)">';

            html += '<span name="cname">'+e.cname+'</span>';

            html += '<span name="vtime">'+(e.vtime/60)+'小时</span>';

            html += '<span name="expire"></span></div>';

        });

        $("#chest").innerHTML = html;



        chest.forEach(e=>$("#index_"+e.cIndex).children["expire"].value = e.expire);

   

        html = "";

        history.forEach(e=>html += "" == html ? e : "<br>"+e);

        $("#history").innerHTML = html;



        if (chest.length && setting.cIndex) {

            $("#index_"+setting.cIndex).children["prior"].checked = !0;

            if ($("#index_"+setting.cIndex).children["expire"].value == 0) { 

                $("#index_"+setting.cIndex).children["expire"].innerText = "下轮优先";

                $("#index_"+setting.cIndex).children["expire"].style.color = state.running ? "purple": "black";

            }

        }



        $("#state").innerText = state.running ? "运行中" : "未运行";

        $("#state").style.backgroundColor = state.running ? "greenyellow" : "#aaa";

        $("#state").style.borderRadius = "2px";



        $("#action").innerText = state.running ? "停止" : "启动";



        window.timer || (window.timer = setInterval(onTimer, 1000));

        onTimer();

    }



    function action() {

        var o = parent.helper.pro.dwarfMiner;

        o.state.running ? o.suspend() : o.startup();

    }

</script>

</head>

<body>

    <h3>矿产大亨活动</h3>

    <div class="panel" id="chest">

    </div>

    <div class="panel">

        <div class="scrollview" id="history">

        </div>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
