helper['pro']['relicResource']["html"] = String["raw"]`<html charset="UTF-8">

<head>

<style>

    html{overflow:hidden;}

    body{line-height:30px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    button{border:1px solid #999; border-radius:3px; outline:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);} 

    table{position:relative; border-collapse:separate; border:0; width:100%;}

    th,td{border-right:1px solid #bbb; border-bottom:1px solid #bbb;}

    th{border-top:1px solid #bbb;} td:first-child,th:first-child{border-left:1px solid #bbb;}

    th,td{padding:5px 4px 2px; text-align:left; white-space:nowrap; line-height:12px; font-size:12px;}

    th{background-color:#ddd;} td{background-color:white;}

    th{position:sticky; position:-webkit-sticky; top:0; z-index:1}

    span{margin-left:16px;}

    dialog{

        position:absolute; margin:0; left:148px; top:290px; width:180px; padding:0 10px; outline:none;

        border:1px solid silver; border-radius:6px; box-shadow:3px 3px 6px gray; overflow:hidden; z-index:3;

    }



    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:6px; box-shadow:3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; text-align:center; align-items:center; width:100%;} 

    .scrollview{overflow-x:auto; overflow-y:auto;}

    .scrollview::-webkit-scrollbar{width:8px; height:8px;} 

    .scrollview::-webkit-scrollbar-track {background:rgb(240, 240, 240); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb {background:rgb(208, 208, 208); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:hover{background:rgb(176, 176, 176); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:active {background:rgb(144, 144, 144); border-radius:8px;} 

    

    #resinfo{height:250px;} #download{margin-left:20px}

</style>

<script>

    function $(a) {

        return a && '#'==a[0] && document.getElementById(a.substring(1));

    }



    function render(resources, cdtime) {

        $('#resources').children[1].innerHTML = "";

        for (var i=0; i<resources.length; ++i) {

            var e = resources[i];



            var row = document.createElement('tr');

            var col = document.createElement('td');

            col.innerText = (i+1).toString();

            row.appendChild(col);

            

            //资源坐标

            col = document.createElement('td');

            col.innerHTML = '<a href="javascript:void(0);" onclick="parent.helper.pro.relicResource.goto(this)">' + e.x + ',' + e.y + '</a>';

            row.appendChild(col);

            

            //资源类型

            col = document.createElement('td');

            col.innerText = e.text;

            row.appendChild(col);



            //刷新时间

            col = document.createElement('td');

            var t = new Date((e.r.expireTime - 14400)*1000);

            col.innerText = (t.getMonth()+1) + '-' + t.getDate() + ' ' + t.getHours() + ':' + t.getMinutes().toString().padStart(2,'0') + ":" + t.getSeconds().toString().padStart(2,'0');

            row.appendChild(col);



            //采集人

            col = document.createElement('td');

            col.innerText = e.r.playerInfo ? JSON.parse(e.r.playerInfo).username : '';

            row.appendChild(col);



            //采集时间

            col = document.createElement('td');

            var t = new Date(e.gatherTime*1000);

            col.innerText = e.gatherTime ? (t.getMonth()+1) + '-' + t.getDate() + ' ' + t.getHours() + ':' + t.getMinutes().toString().padStart(2,'0') + ":" + t.getSeconds().toString().padStart(2,'0') : '';

            row.appendChild(col);



            $('#resources').children[1].appendChild(row);

        }

        setTimeout(()=>{$('#refresh').disabled = !1}, cdtime - Date.now());

    }



    function refresh() {

        $('#refresh').disabled = !0;

        parent.helper.pro.relicResource.refresh();

    }



    function download() { 

        var html = "<html><head><meta charset='utf-8' /></head><body>" + document.getElementsByTagName("table")[0].outerHTML + "</body></html>";

        var blob = new Blob([html], { type: "application/vnd.ms-excel" });



        var a = document.createElement('a');

        a.href = URL.createObjectURL(blob), a.download = "relic-resource.xls", a.style.display = 'none';

        document.body.appendChild(a) && a.click() && document.body.removeChild(a);

    }

</script>

</head>

<body>

    <h3>遗迹资源信息</h3>

    <div class="panel">

        <div class="scrollview" id="resinfo">

            <table id="resources" cellspacing="0" cellpadding="0">

                <thead>

                    <tr><th>序号</th><th>资源坐标</th><th>资源类型</th><th>刷新时间</th><th>采集人</th><th>采集时间</th></tr>

                </thead>

                <tbody>

                </tbody>

            </table>

        </div>

    </div>

    <div class="foot">

        <div style="margin:auto; line-height:13px;">

            <button id="refresh" onclick="refresh()">刷新</button>

            <button id="download" onclick="download()">下载</button>

        </div>

    </div>

</body>

</html>`;
