helper["pro"]['crossTreasure']['html'] = String["raw"]`<html charset="UTF-8">

<head>

<style>

    html{overflow:hidden;} 

    body{line-height:30px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    label,span{display:inline-block; height:13px; line-height:13px;} i{margin-left:4px;}

    input[type=checkbox]{margin-left:2px; margin-right:1px; margin-top:8px; vertical-align:top; width:13px; height:13px;  accent-color:gray;}

    input{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; padding:1px 2px; width:120px; height:16.667px;} input::placeholder{color: #aaa;}

    select{color:#333; border:1px solid #999; border-radius:3px; outline-style:none; margin-left:0px; padding-top:0px; width:68px; height:20px; font-size:13px;} 

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);}

    ul{display:flex; margin:4px; margin-top:0px; margin-bottom:8px; list-style-type:none; flex-flow:wrap; padding-inline-start:0px;}

    li{margin:4px; margin-left:0px; margin-right:8px; padding-left:12px; text-align:left; width:70px; height:26px; background:#ddd; border-radius:2px;}

    

    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:8px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; padding-bottom:2px; align-items:center; width:100%;} 

    .combo-box{display:inline-block; position:relative; width:65px; height:20px;} .combo-list{width:100%;}

    .combo-edit{position:absolute; height:13px; width:45px; left:2px; top:7px; outline-style:none; border:0px; padding-left:2px; background-color:transparent; font-size:13px;}

    .scrollview{overflow-x:auto; overflow-y:auto;}

    .scrollview::-webkit-scrollbar{width:8px; height:8px;} 

    .scrollview::-webkit-scrollbar-track {background:rgb(240, 240, 240); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb {background:rgb(208, 208, 208); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:hover{background:rgb(176, 176, 176); border-radius:8px;}

    .scrollview::-webkit-scrollbar-thumb:active {background:rgb(144, 144, 144); border-radius:8px;}

    

    #parteners{width:145px}

    #div_popup{position:absolute; border:1px solid silver; border-radius:4px; box-shadow:4px 4px 8px gray; overflow:hidden; allow-transparency: true; background-color: #f8f8f8; z-index:1; margin:0; padding:4px 0px 6px 4px; left:50%; top:50%; transform:translate(-50%, -50%)}

    #counter{display:inline-block; color:green; width:100px;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

</style>

<script src="${helper['jquery_url']}"></script>

<script>

    function onload() {

        div_popup.addEventListener('click', (e)=>e.stopPropagation());

        document.addEventListener('click', ()=>div_popup.style.display = 'none');

        $("#priority").sortable({update:apply});

    }



    function editchange(edit) {

        edit.setAttribute("value", Number(edit.value.replace('次','').replace('秒','').replace('内',''))); 

        apply();   

    }



    function listchange(list) {

        var edit = list.parentNode.children["edit"];

        var i = list.selectedIndex;

        edit.value = list.options[i].innerText;

        edit.setAttribute("value", list.options[i].value);

        list.selectedIndex = 0;

        apply();

    }



    function apply() {

        var setting = {team:{}, hunt:{skill:{priority:{}}, items:[]}};



        setting.team.mode = Number($("#mode").val());

        setting.team.preset = Number($("#preset").val());

        setting.team.size = Number($("#size").val());

        setting.team.useitem = $("#useitem").prop('checked');

        setting.team.share = $("#share").prop('checked');

        setting.team.count = Number($("#count").children('[name="edit"]').attr("value"));

        setting.team.parteners = $("#parteners").val().split(' ').filter(e=>e).splice(0,4);



        for(var a = $("#priority").children(), i = 0; i < a.length; i++) setting.hunt.skill.priority[a[i].value] = i+1;

        for(var i = 1; i <= 6; i++) {

            $("#dbl_item_"+i).prop("checked") && (setting.hunt.items = setting.hunt.items.concat($("#dbl_item_"+i).prop("value").split(',').map(e=>Number(e))));

        }

        parent.helper.pro.crossTreasure.apply(setting);

    }



    function render(setting, state) {

        $("#mode").val(setting.team.mode);

        $("#preset").val(setting.team.preset);

        $("#size").val(setting.team.size);

        $("#useitem").prop('checked', setting.team.useitem);

        $("#share").prop('checked', setting.team.share);

        $("#count").children('[name="edit"]').val(99999 == setting.team.count ? '无限次' : setting.team.count + '次');

        $("#count").children('[name="edit"]').attr("value", setting.team.count);

        $("#count").children('[name="list"]').val('');

        $("#counter").text(state.counter ? '已夺宝' + state.counter + '次' : '');

        $("#counter").css("color", state.counter >= setting.team.count ? "green" : state.running ? "purple" : "black");

        $("#parteners").val(setting.team.parteners.join(' '));



        $("#label_size").css("color", setting.team.mode == 1 ? "black" : "gray"); 

        $("#size").prop('disabled', setting.team.mode != 1);

        $("#priority").html("");

        var a = Object.entries(setting.hunt.skill.priority).sort((e,t)=>e[1] - t[1]);

        for(var e of a) {

            var li = document.createElement('li');

            li.value = e[0];

            li.innerText = parent.LOCAL.getText(Object.values(parent.TABLE.getTableGroup(parent.TableName.cross_treasure_skill)).find(t=>t.type == e[0])?.name);

            $("#priority").append(li);

        }

        for(var i = 1; i <= 6; i++) $("#dbl_item_"+i).prop("checked", !!setting.hunt.items.find(e=>$("#dbl_item_"+i).prop("value").split(',').map(e=>Number(e)).includes(e)));



        $("#state").text(state.running ? "运行中" : "未运行");

        $("#state").css("backgroundColor", state.running ? "greenyellow" : "#aaa");

        $("#state").css("borderRadius", "2px");

        $("#action").text(state.running ? "停止" : "启动");

    }



    function action() {

        var o = parent.helper.pro.crossTreasure;

        o.state.running ? o.suspend() : o.startup();

    }

    function show_dbl_item() {

        div_popup.style.display='block';

        event.stopPropagation();

    }

</script>

</head>

<body onload="onload()">

    <h3>夺宝奇兵活动</h3>

    <div class="panel" id="team">

        <span>模式:</span>

        <select id="mode" onchange="apply()">

            <option value=1>队长</option>

            <option value=2>成员</option>

            <option value=3>小号</option>

            <option value=4>陪跑</option>

        </select>

        <i></i><i></i><i></i>

        <span id="label_size">人数:</span>

        <select id="size" onchange="apply()">

            <option value=2>2人</option>

            <option value=3>3人</option>

            <option value=4>4人</option>

            <option value=5>5人</option>

        </select>

        <i></i><i></i><i></i>

        <span>编队:</span>

        <select id="preset" onchange="apply()">

            <option value=-1>单兵</option>

            <option value=1>编队1</option>

            <option value=2>编队2</option>

            <option value=3>编队3</option>

            <option value=4>编队4</option>

            <option value=5>编队5</option>

            <option value=6>编队6</option>

            <option value=7>编队7</option>

            <option value=8>编队8</option>

            <option value=9>编队9</option>

            <option value=0>自动</option>

        </select>

        <i></i><i></i><i></i>

        <span>次数:</span>

        <div id="count" class="combo-box">

            <select class="combo-list" name="list" onchange="listchange(this)">

                <option value=1>1次</option>

                <option value=3>3次</option>

                <option value=5>5次</option>

                <option value="99999">无限次</option>

            </select>

            <input class="combo-edit" name="edit" onchange="editchange(this)">

        </div>

        <br>

        <input type="checkbox" id="useitem" onclick="apply()"><label for="useitem">补充信标</label>

        <i></i>

        <input type="checkbox" id="share" onclick="apply()"><label for="share">分享联盟</label>

        <i></i>

        <span>好友:</span>

        <input id="parteners" placeholder="空格分隔多个好友" value="" onchange="apply()">

        <i></i><i></i><i></i>

        <span id="counter"></span>

    </div>

    <div class="panel" id="hunt">

        <span style="margin-left:4px">技能领取优先级顺序:</span>

        <a style="margin-left:12px; color:#8B4513; font-weight:bold;" href="javascript:;" onclick="show_dbl_item()">设置双倍奖励道具</a>

        <div class="scrollview" id="content">

            <ul class="list" id="priority" onsortupdate="apply()">

                <li>1</li>

                <li>2</li>

                <li>3</li>

                <li>4</li>

                <li>5</li>

            </ul>

        </div> 

    </div>

    <div id="div_popup" class="panel" style="display:none; width:400px; padding-left:16px">

        <input type="checkbox" id="dbl_item_1" value="820017" onclick="apply()"><label style="width:90px" for="dbl_item_1">顶级催化剂</label><i></i>

        <input type="checkbox" id="dbl_item_2" value="801040" onclick="apply()"><label style="width:100px" for="dbl_item_2">装备改造图纸</label><i></i>

        <input type="checkbox" id="dbl_item_3" value="69559,42000003" onclick="apply()"><label for="idbl_item_3">超级重装芯片宝箱</label><br>

        <input type="checkbox" id="dbl_item_4" value="1001803,23044405" onclick="apply()"><label style="width:90px" for="dbl_item_4">同频器自选箱</label><i></i>

        <input type="checkbox" id="dbl_item_5" value="20213232" onclick="apply()"><label style="width:100px" for="idbl_item_5">万能装饰物碎片</label><i></i>

        <input type="checkbox" id="dbl_item_6" value="39200167" onclick="apply()"><label for="dbl_item_6">3级稀有技能自选箱</label>

    </div>

    <div class="foot">

        <span id="state">未运行</span>

        <button id="action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
