helper["pro"]['miscController']["html"] = String['raw']`<html charset="UTF-8">

<head>

<style>

    html{overflow:hidden;}

    body{line-height:26px; font-size:13px; font-family:"Helvetica","Lucida Console","Microsoft soft"; user-select:none;}

    h3{display:block; margin-top:12px; margin-bottom:8px; text-align:center; width:100%}

    h4{display:block; margin:0px; text-align:center; width:100%}

    label,span{display:inline-block; width:76px; height:13px; line-height:13px;}

    input[type=checkbox]{margin-left:2px; margin-right:1px; margin-top:6px; vertical-align:top; width:13px; height:13px; accent-color:gray;}

    button{border:1px solid #999; border-radius:3px; outline-style:none; text-align:center; margin-top:0px; width:80px; height:22px;}

    button:hover{background-color:#ccc;} button:focus{background-color:#ccc;} button:active{transform: translateY(1px);}

    .panel{border:1px solid silver; border-radius:6px; margin:4px; padding:4px; padding-left:12px; box-shadow: 3px 3px 6px gray;}

    .foot{display:flex; margin-top:12px; align-items:center; width:100%;}

    .mtips{color:#777;font-size:11px;}

    #state{margin-left:4px; width:45px; text-align:center;} #action{margin:auto;} #dummy{margin-right:4px; width:45px}

    .combo-box{display:inline-block; position:relative; width:65px; height:20px;} .combo-list{width:100%;}

    .combo-edit{position:absolute; height:13px; width:45px; margin-left:0px; left:2px; top:5px; outline-style:none; border:0px; padding-left:2px; background-color:transparent; font-size:13px;}



    #div_popup{position:absolute; border:1px solid silver; border-radius:4px; box-shadow:2px 2px 4px gray; overflow:hidden; allow-transparency: true; background-color: #fff; z-index:3; margin:0; padding:6px; left:50%; top:50%; transform:translate(-50%, -50%)}

    #lb_state{margin-left:4px; width:45px; text-align:center;} #bt_action{margin:auto;} #dummy{margin-right:4px; width:45px}

    .arrow {display: inline-block;margin-left: 2px;width: 0;height: 0;border-left: 3px solid transparent;border-right: 3px solid transparent;border-top: 5px solid #555;vertical-align: 2px;transition: transform 0.2s ease;}

.arrow.up {transform: rotate(180deg);}

</style>   

<script src="${helper["jquery_url"]}"></script>

<script>

    function editchange(edit) {

        edit.setAttribute('value', Number(edit.value.replace('次','').replace('秒','').replace('内','').replace('到达','')));

        apply_param && apply_param();

    }

    function listchange(list) {

        var edit = list.parentNode.children["edit"];

        var i = list.selectedIndex;

        edit.value = list.options[i].innerText;

        edit.setAttribute('value', list.options[i].value);

        apply_param && apply_param();

    }

    function render(setting, state) {

        var html = '', i = 0;

        for(var e in setting) {

            html += '<input type="checkbox" id="' + e + '" onclick="apply()"><span id="lb_' + e + '" onclick="set_param(this.innerText)">' + setting[e].text + (parent.helper.pro.misc[e]?.html ? '<i class="arrow"></i>' : '') + '</span>';

            ++i % 5 == 0 && (html = html + '<br>');

        }

        html += '<div class="mtips">名字带三角图标的可点开设置参数</div>';

        html = html.replace(/<br>+$/, '');

        div_panel.innerHTML = html;

        for(var e in setting) {

            document.getElementById(e).checked = setting[e].active;

            document.getElementById(e).disabled = e === 'gameTools' ? true : !parent.helper.pro.misc[e];

        }



        for(var e in setting) {

            parent.helper.pro.misc[e]?.html && (document.getElementById("lb_"+e).style.cursor = 'pointer');

        }



        lb_state.innerText = state.running ? "运行中" : "未运行";

        lb_state.style.backgroundColor = state.running ? "greenyellow" : "#aaa";

        lb_state.style.borderRadius = "2px";



        bt_action.innerText = state.running ? "停止" : "启动";

    }

    function set_param(text) {

        var setting = parent.helper.pro.miscController.setting;

        var name = Object.keys(setting).find(e=>setting[e].text == text);

        var html = parent.helper.pro.misc[name]?.html;

        var currentArrow = document.querySelector('#lb_' + name + ' .arrow');

    

        if (currentArrow && currentArrow.classList.contains('up')) {

         currentArrow.classList.remove('up');

         div_popup.style.display = 'none';

         return;

        }

    

        var allArrows = document.querySelectorAll('.arrow.up');

          allArrows.forEach(function(arrow) {

          arrow.classList.remove('up');

        });

        if (currentArrow) {

          currentArrow.classList.add('up');

        }

        if (html) {

            h4_title.innerText = setting[name].text + '参数';

            const range = document.createRange();

            const fragment = range.createContextualFragment(html);

            div_param.innerHTML = '';

            div_param.appendChild(fragment);

            parent.helper.pro.misc[name].render();



            div_popup.style.backgroundColor = '#e6f2ff';

            div_popup.style.display = 'block';

            event.stopPropagation();

        }

    }



    function apply() {

        var a = document.getElementsByTagName("input"), setting = {};

        for(var e of a) setting[e.id] = e.checked;

        parent.helper.pro.miscController.apply(setting);

    }



    function action() {

        var o = parent.helper.pro.miscController;

        o.state.running ? o.suspend() : o.startup();

    }



    function onload() {    

        div_popup.addEventListener('click', (e)=>e.stopPropagation());

        //document.addEventListener('click', ()=>div_popup.style.display = 'none');

        document.addEventListener('click', function() {

        div_popup.style.display = 'none';

        var allArrows = document.querySelectorAll('.arrow.up');

        allArrows.forEach(function(arrow) {

          arrow.classList.remove('up');

         });

       });

    }

</script>

</head>

<body onload="onload()">

    <h3>其他更多活动</h3>

    <div id="div_panel" class="panel">

    </div>

    <div id="div_popup" class="panel" style="display:none">

        <h4 id="h4_title"></h4>

        <div id="div_param"></div>

    </div>

    <div class="foot">

        <span id="lb_state">未运行</span>

        <button id="bt_action" onclick="action()">启动</button>

        <span id="dummy"></span>

    </div>

</body>

</html>`;
