helper['pro']["misc"]['truck']["html"] = String["raw"]`<script>

    function render_param(setting, state) {

            const tids = setting.lootItemIds || [];

            truck_ids1.checked = tids.includes(820016);

            truck_ids2.checked = tids.includes(820015);

            truck_ids3.checked = tids.includes(69359);

            truck_ids4.checked = tids.includes(69159);

            truck_ids5.checked = tids.includes(2300003);

            truck_ids6.checked = tids.includes(1600029);

        truck_grade.value = setting.grade || 4;

        reload_limit.value = setting.reloadCount;

        sendtruck.checked = setting.sendTruck;

        sendtrain.checked = setting.sendTrain;

        intercept.checked = setting.intercept;

        intercept_train.checked = setting.intercept_train;

        reload_counter.innerText = '已刷'+state.reloadCounter+'次, 已截'+state.interceptCounter+'次';

        reload_counter.style.color = state.reloadCounter == setting.reloadCount ? 'green' : parent.helper.pro.misc.truck.timer ? 'purple' : 'black';

    }

    

    function apply_param() {

        var setting = {

            lootItemIds:[truck_ids1.checked ? 820016 : null,truck_ids2.checked ? 820015 : null,truck_ids3.checked ? 69359 : null,truck_ids4.checked ? 69159 : null,truck_ids5.checked ? 2300003 : null,truck_ids6.checked ? 1600029 : null].filter(Boolean),

            reloadCount: Number(reload_limit.value),

            sendTruck: sendtruck.checked,

            sendTrain: sendtrain.checked,

            intercept: intercept.checked,

            intercept_train: intercept_train.checked,

            grade: Number(truck_grade.value)

        };

        parent.helper.pro.misc.truck.apply(setting);

    }

</script>

<div style="width:420px">

    <input type="checkbox" id="sendtruck" style="margin-left:4px; margin-top:7px" onchange="apply_param()"><label for="sendtruck" style="display:inline">自动发卡车</label>



    <input type="checkbox" id="sendtrain" style="margin-left:8px" onchange="apply_param()"><label for="sendtrain" style="display:inline">自动发列车</label>

     <span style="display:inline; margin-left:8px">卡车发车等级:</span>

     <select id="truck_grade" style="width:130px" onchange="apply_param()">

                <option value=5>传奇</option>

                <option value=4>史诗及以上</option>

                <option value=3>稀有及以上</option>

                <option value=2>高级及以上</option>

                <option value=1>普通及以上</option>

            </select>

    <br>

    <input type="checkbox" id="intercept" style="margin-left:4px" onchange="apply_param()"><label for="intercept" style="display:inline">拦截卡车</label>



    <input type="checkbox" id="intercept_train" style="margin-left:20px" onchange="apply_param()"><label for="intercept_train" style="display:inline">拦截列车</label>

    <span style="display:inline; margin-left:22px">拦截刷新上限:</span>

    <select id="reload_limit" style="width:130px" onchange="apply_param()">

        <option value=500>500次</option>

        <option value=1000>1000次</option>

        <option value=2000>2000次</option>

        <option value=3000>3000次</option>

        <option value=999999>无限次</option>

    </select>

    <br>

    <span style="display:inline; margin-left:4px">拦截道具:</span>

<i style="margin-left:8px"></i>

<input type="checkbox" id="truck_ids1" onchange="apply_param()">

<label for="truck_ids1" style="display:inline">紫催</label>

<input type="checkbox" id="truck_ids2" onchange="apply_param()">

<label for="truck_ids2" style="display:inline">蓝催</label>

<input type="checkbox" id="truck_ids3" onchange="apply_param()">

<label for="truck_ids3" style="display:inline">紫芯片</label>

<input type="checkbox" id="truck_ids4" onchange="apply_param()">

<label for="truck_ids4" style="display:inline">蓝芯片</label>

<input type="checkbox" id="truck_ids5" onchange="apply_param()">

<label for="truck_ids5" style="display:inline">金碎</label>

<input type="checkbox" id="truck_ids6" onchange="apply_param()">

<label for="truck_ids6" style="display:inline">职业箱</label>

    <br>

    <span id="reload_counter" style="width:130px; margin-left:4px"></span>

    <span style="color:#FF9900; display:inline">刷新超过1000次有封号风险，请谨慎选择。</span><br>

    <span style="color:#777; display:inline-block; width:auto; margin-left:4px;">如果长时间不刷新，请检查快攻1队士兵是否充足。</span>

</div>`;
