        shop_stay_time.children["edit"].style.color = shop_stay_time.children["edit"].disabled ? '#999' : 'black';

        shop_stay_time.children["list"].style.color = shop_stay_time.children["list"].disabled ? '#999' : 'black';

        label_shop_stay_time.style.color = shop_stay_time.children["edit"].disabled ? '#999' : 'black';



        res_stay_time.children["edit"].disabled = !setting.option.auto_march;

        res_stay_time.children["list"].disabled = !setting.option.auto_march;

