            join_round: Number(join_round.value),

            team_mode: Number(team_mode.value),

            team_type: Number(team_type.value),

            plane_time: Number(plane_time.children["edit"].getAttribute("value")),

            cure_num: Number(cure_num.value), 

            drop_num: Number(drop_num.value),

            march_policy: Number(march_policy.value),

            beast_policy: Number(beast_policy.value),

